import{_ as a,o as d,c as r,ag as e}from"./chunks/framework.CNG7EpJN.js";const p=JSON.parse('{"title":"管理ダッシュボード","description":"","frontmatter":{"title":"管理ダッシュボード"},"headers":[],"relativePath":"tenant/03-dashboard.md","filePath":"tenant/03-dashboard.md"}'),o={name:"tenant/03-dashboard.md"};function h(l,t,i,n,s,b){return d(),r("div",null,[...t[0]||(t[0]=[e('<h1 id="_3-管理ダッシュボード" tabindex="-1">3. 管理ダッシュボード <a class="header-anchor" href="#_3-管理ダッシュボード" aria-label="Permalink to &quot;3. 管理ダッシュボード&quot;">​</a></h1><p>管理ダッシュボードは、店舗運営に必要な設定と確認を行う画面です。ログインしたユーザーのロールに応じて、表示されるタブが変わります。</p><h2 id="画面の基本構成" tabindex="-1">画面の基本構成 <a class="header-anchor" href="#画面の基本構成" aria-label="Permalink to &quot;画面の基本構成&quot;">​</a></h2><table tabindex="0"><thead><tr><th>場所</th><th>内容</th></tr></thead><tbody><tr><td>ヘッダー</td><td>店舗名、店舗切替、ログイン中のユーザー名、パスワード変更</td></tr><tr><td><strong>週次サマリー</strong></td><td>直近1週間の売上推移、前週比、客数、人気商品Top3を視覚的に表示するカード。</td></tr><tr><td>メインタブ</td><td>メニュー、注文、レポート、店舗設定などの機能切替</td></tr><tr><td>サブタブ</td><td>各機能の中の詳細メニュー</td></tr><tr><td>右下のサポートガイド</td><td>操作で困ったときに FAQ・キーワード検索・症状別の案内・エラー番号から調べられるヘルプボタン</td></tr></tbody></table><h2 id="週次サマリー-売上タブ" tabindex="-1">週次サマリー（売上タブ） <a class="header-anchor" href="#週次サマリー-売上タブ" aria-label="Permalink to &quot;週次サマリー（売上タブ）&quot;">​</a></h2><p>店舗ダッシュボードの「売上」タブの先頭に、直近1週間の状況を即座に把握するための「週次サマリー」が表示されます。</p><h3 id="確認できる項目" tabindex="-1">確認できる項目 <a class="header-anchor" href="#確認できる項目" aria-label="Permalink to &quot;確認できる項目&quot;">​</a></h3><ul><li><strong>主要な4つの数値（KPI）</strong>: 直近7日間の売上合計、客数、客単価、および前週との比較（％）を確認できます。</li><li><strong>人気商品 Top 3</strong>: その週に最も注文された上位3商品が表示され、仕入れやメニュー構成の参考にできます。</li></ul><h2 id="ロール別の表示" tabindex="-1">ロール別の表示 <a class="header-anchor" href="#ロール別の表示" aria-label="Permalink to &quot;ロール別の表示&quot;">​</a></h2><table tabindex="0"><thead><tr><th>ロール</th><th>主に表示される内容</th></tr></thead><tbody><tr><td>オーナー</td><td>複数店舗管理、本部機能、契約・決済設定、ユーザー管理</td></tr><tr><td>マネージャー</td><td>担当店舗のメニュー、注文、会計、在庫、シフト、レポート、店舗設定</td></tr><tr><td>スタッフ</td><td>勤怠打刻、マイシフト、希望シフト提出</td></tr></tbody></table><p>表示されないタブがある場合は、権限または所属店舗が不足している可能性があります。</p><h2 id="店舗を切り替える" tabindex="-1">店舗を切り替える <a class="header-anchor" href="#店舗を切り替える" aria-label="Permalink to &quot;店舗を切り替える&quot;">​</a></h2><p>複数店舗に所属している場合は、画面上部の店舗セレクターから操作対象の店舗を選びます。選択した店舗に対して、メニュー、注文、レポートなどの操作が行われます。</p><h2 id="サポートガイドを使う-右下の-📚-ボタン" tabindex="-1">サポートガイドを使う (右下の 📚 ボタン) <a class="header-anchor" href="#サポートガイドを使う-右下の-📚-ボタン" aria-label="Permalink to &quot;サポートガイドを使う (右下の 📚 ボタン)&quot;">​</a></h2><p>管理画面右下の <strong>「📚 サポートガイド」</strong> (オレンジ色の丸ボタン) から、操作で困った時の情報を検索できます。</p><p><strong>5 つの入口:</strong></p><table tabindex="0"><thead><tr><th>入口</th><th>用途</th></tr></thead><tbody><tr><td>ホーム</td><td>カテゴリ別ショートカット + 人気の質問 + エラー番号入力欄</td></tr><tr><td>よくある質問 (FAQ)</td><td>カテゴリ別に厳選した Q&amp;A (ログイン・注文・会計・印刷・予約・KDS・メニュー・シフト・テイクアウト・設定)</td></tr><tr><td>キーワード検索</td><td>「会計」「パスワード」「予約」「プリンタ」などで FAQ / 案内記事 / エラーコードを横断検索</td></tr><tr><td>症状からたどる</td><td>「ログインできない」「KDSに出ない」等の症状からステップバイステップの対処手順</td></tr><tr><td>エラー番号</td><td><code>E3024</code> 等を入力すると意味と対処を即座に表示</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">まずはサポートガイドをご利用ください</p><p>サポートガイドには、よくあるお問い合わせと基本的な対処方法をまとめています。該当する案内が見つからない場合は、POSLAサポートへお問い合わせください。</p></div><h2 id="操作時の注意" tabindex="-1">操作時の注意 <a class="header-anchor" href="#操作時の注意" aria-label="Permalink to &quot;操作時の注意&quot;">​</a></h2><ul><li>複数店舗を管理している場合は、操作前に選択中の店舗名を確認してください。</li><li>スタッフアカウントでは、店舗運営に必要な一部機能のみ表示されます。</li><li>画面表示が古い場合は、ブラウザの再読み込みを行ってください。</li></ul><h2 id="困ったとき" tabindex="-1">困ったとき <a class="header-anchor" href="#困ったとき" aria-label="Permalink to &quot;困ったとき&quot;">​</a></h2><table tabindex="0"><thead><tr><th>症状</th><th>対処</th></tr></thead><tbody><tr><td>タブが表示されない</td><td>権限と所属店舗を確認してください。</td></tr><tr><td>店舗が選べない</td><td>オーナーまたはマネージャーに所属店舗の設定を確認してください。</td></tr><tr><td>読み込みに失敗する</td><td>再読み込みし、改善しない場合はPOSLAサポートへお問い合わせください。</td></tr></tbody></table>',22)])])}const u=a(o,[["render",h]]);export{p as __pageData,u as default};
